# Stale fact eviction: when a user provides a correction, find and remove
# the old fact from the authoritative store before adding the new one.

from openai import OpenAI

client = OpenAI(api_key='...')

class AuthoritativeFacts:
    """Append-only store with explicit supersession."""

    def __init__(self):
        self.facts: list[dict] = []   # {id, text, superseded_by}
        self._next_id = 0

    def add(self, text: str) -> int:
        fid = self._next_id
        self.facts.append({'id': fid, 'text': text, 'superseded_by': None})
        self._next_id += 1
        return fid

    def supersede(self, old_id: int, new_text: str) -> int:
        new_id = self.add(new_text)
        for f in self.facts:
            if f['id'] == old_id:
                f['superseded_by'] = new_id
        return new_id

    def current_facts(self) -> list[str]:
        """Return only non-superseded facts."""
        return [f['text'] for f in self.facts if f['superseded_by'] is None]

    def detect_contradiction(self, new_text: str) -> int | None:
        """Return the id of an existing fact that new_text contradicts, or None."""
        for f in self.facts:
            if f['superseded_by'] is not None:
                continue
            prompt = (
                f"Does statement B contradict statement A? Reply YES or NO only.\n"
                f"A: {f['text']}\nB: {new_text}"
            )
            resp = client.chat.completions.create(
                model='gpt-4o-mini',
                messages=[{'role': 'user', 'content': prompt}],
                max_tokens=3, temperature=0,
            )
            if resp.choices[0].message.content.strip().upper().startswith('YES'):
                return f['id']
        return None

    def add_or_supersede(self, new_text: str) -> int:
        """Add new_text, superseding any contradicting existing fact."""
        old_id = self.detect_contradiction(new_text)
        if old_id is not None:
            print(f'Superseding fact {old_id}.')
            return self.supersede(old_id, new_text)
        return self.add(new_text)


store = AuthoritativeFacts()
store.add('The deadline is December 15.')
store.add('Alice is the tech lead.')
store.add_or_supersede('The deadline was extended to January 15.')  # supersedes Dec 15
print(store.current_facts())
# ['Alice is the tech lead.', 'The deadline was extended to January 15.']
